def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query]).astype("float32")
    _, faiss_idx = index.search(query_vec, 100)
    faiss_idx = faiss_idx[0]

    bm25_scores = bm25.get_scores(query.lower().split())
    bm25_idx = np.argsort(bm25_scores)[-100:]

    combined_ranks = {}
    for i, idx in enumerate(faiss_idx):
        combined_ranks[idx] = combined_ranks.get(idx, 0) + 1 / (i + 1 + 60)
    for i, idx in enumerate(bm25_idx):
        combined_ranks[idx] = combined_ranks.get(idx, 0) + 1 / (i + 1 + 60)

    top_idx = sorted(combined_ranks, key=combined_ranks.get, reverse=True)[:top_k]
    return df.iloc[top_idx][["title", "overview"]].to_dict("records")

