def search(query, df, bm25, model, index, top_k=10):
    vec = model.encode([query])
    _, top_idx = index.search(vec.astype("float32"), top_k * 5)
    candidates = df.iloc[top_idx[0]].copy()

    # Simple genre boost if query mentions genre keywords
    q_low = query.lower()
    for genre in ['action', 'comedy', 'drama', 'horror', 'romance', 'sci-fi', 'thriller']:
        if genre in q_low:
            candidates['score'] = candidates['genres'].apply(lambda x: 1.1 if genre in x.lower() else 1.0)
            candidates = candidates.sort_values('score', ascending=False)
            break

    return candidates.iloc[:top_k][["title", "overview"]].to_dict("records")

