def search(query, df, bm25, model, index, top_k=10):
    query_tokens = query.lower().split()
    bm25_scores = bm25.get_scores(query_tokens)

    vec = model.encode([query])
    dists, top_idx = index.search(vec.astype("float32"), 100)

    rrf_scores = {}
    # BM25 RRF
    bm25_order = np.argsort(bm25_scores)[::-1]
    for rank, idx in enumerate(bm25_order[:100]):
        rrf_scores[idx] = rrf_scores.get(idx, 0) + 1 / (60 + rank)

    # FAISS RRF
    for rank, idx in enumerate(top_idx[0]):
        rrf_scores[idx] = rrf_scores.get(idx, 0) + 1 / (60 + rank)

    sorted_idx = sorted(rrf_scores, key=rrf_scores.get, reverse=True)
    return df.iloc[sorted_idx[:top_k]][["title", "overview"]].to_dict("records")

