def search(query, df, bm25, model, index, top_k=10):
    # Vector Search
    query_vec = model.encode([query])
    dists, faiss_idx = index.search(query_vec.astype("float32"), 100)

    # BM25 Search
    bm25_scores = bm25.get_scores(query.lower().split())
    bm25_idx = np.argsort(bm25_scores)[::-1][:100]

    # RRF
    ranks = {}
    for i, idx in enumerate(faiss_idx[0]):
        ranks[idx] = ranks.get(idx, 0) + 1 / (60 + i)
    for i, idx in enumerate(bm25_idx):
        ranks[idx] = ranks.get(idx, 0) + 1 / (60 + i)

    top_idx = sorted(ranks, key=ranks.get, reverse=True)[:top_k]
    return df.iloc[top_idx].to_dict("records")
